// Shared SYNK logo image data (white-on-transparent). Used by logo-animation components.
// SSR-safe: exports the object and (in a browser) also exposes window.SYNK_LOGO
// so the standalone <script src> usage keeps working.
const SYNK_LOGO = {
  full: 'data:image/png;base64,',
  top: 'data:image/png;base64,',
  bot: 'data:image/png;base64,'
};

if (typeof window !== 'undefined') window.SYNK_LOGO = SYNK_LOGO;
export default SYNK_LOGO;
export { SYNK_LOGO };
